# =============================================================================

import sys
from pathlib import Path
import pandas as pd
import numpy as np
from typing import Dict, List, Tuple, Any
import traceback

# Add project root to path for imports
PROJECT_ROOT = Path(__file__).resolve().parents[4]
sys.path.insert(0, str(PROJECT_ROOT))

# Import validation tools
from tools.validation import validate_standardization

# =============================================================================
# Configuration
# =============================================================================

RQ_DIR = Path(__file__).resolve().parents[1]  # results/ch7/7.5.4
LOG_FILE = RQ_DIR / "logs" / "step02_create_person_centered_variables.log"

# =============================================================================
# Logging Function
# =============================================================================

def log(msg):
    """Write to both log file and console."""
    with open(LOG_FILE, 'a', encoding='utf-8') as f:
        f.write(f"{msg}\n")
        f.flush()
    print(msg, flush=True)

# =============================================================================
# Main Analysis
# =============================================================================

if __name__ == "__main__":
    try:
        log("[START] Step 02: create_person_centered_variables")

        # =========================================================================
        # STEP 1: Load Sleep Data
        # =========================================================================
        # Expected: Clean sleep data from step01
        # Purpose: Create person-centered variables for multilevel analysis

        log("[LOAD] Loading sleep data from step01...")
        sleep_input_path = RQ_DIR / "data" / "step01_sleep_data.csv"
        
        if not sleep_input_path.exists():
            log(f"[ERROR] Input file not found: {sleep_input_path}")
            log("[ERROR] Run step01_extract_sleep_data.py first")
            sys.exit(1)
            
        sleep_df = pd.read_csv(sleep_input_path)
        log(f"[LOADED] sleep_data.csv ({len(sleep_df)} rows, {len(sleep_df.columns)} cols)")

        # Check required columns
        required_cols = ["UID", "TEST", "Sleep_Hours", "Sleep_Quality"]
        missing_cols = [col for col in required_cols if col not in sleep_df.columns]
        
        if missing_cols:
            log(f"[ERROR] Missing required columns: {missing_cols}")
            sys.exit(1)

        # =========================================================================
        # STEP 2: Compute Person Means  
        # =========================================================================
        # Direct pandas operation: groupby UID and compute mean sleep variables
        # What it does: Calculate each person's average sleep across all tests
        # Expected output: Person means for Sleep_Hours and Sleep_Quality

        log("[ANALYSIS] Computing person means...")
        
        # Compute person means for sleep variables
        person_means = sleep_df.groupby('UID')[['Sleep_Hours', 'Sleep_Quality']].mean()
        person_means = person_means.rename(columns={
            'Sleep_Hours': 'Sleep_Hours_PM',
            'Sleep_Quality': 'Sleep_Quality_PM'
        })
        
        log(f"[COMPUTED] Person means for {len(person_means)} participants")
        log(f"[MEANS] Sleep_Hours_PM range: {person_means['Sleep_Hours_PM'].min():.1f} - {person_means['Sleep_Hours_PM'].max():.1f}")
        log(f"[MEANS] Sleep_Quality_PM range: {person_means['Sleep_Quality_PM'].min():.1f} - {person_means['Sleep_Quality_PM'].max():.1f}")

        # =========================================================================
        # STEP 3: Create Within-Person Centered Variables
        # =========================================================================
        # Direct pandas operation: merge person means and compute deviations
        # What it does: Calculate within-person deviations from person mean
        # Expected output: Within-person centered sleep variables

        log("[ANALYSIS] Creating within-person centered variables...")
        
        # Merge person means back to original data
        sleep_centered = sleep_df.merge(person_means, on='UID', how='left')
        
        # Compute within-person deviations
        sleep_centered['Sleep_Hours_WP'] = sleep_centered['Sleep_Hours'] - sleep_centered['Sleep_Hours_PM']
        sleep_centered['Sleep_Quality_WP'] = sleep_centered['Sleep_Quality'] - sleep_centered['Sleep_Quality_PM']
        
        log(f"[COMPUTED] Within-person variables for {len(sleep_centered)} observations")
        log(f"[WP] Sleep_Hours_WP range: {sleep_centered['Sleep_Hours_WP'].min():.2f} - {sleep_centered['Sleep_Hours_WP'].max():.2f}")
        log(f"[WP] Sleep_Quality_WP range: {sleep_centered['Sleep_Quality_WP'].min():.2f} - {sleep_centered['Sleep_Quality_WP'].max():.2f}")

        # Verify centering worked (within-person means should be ~0)
        wp_hour_mean = sleep_centered.groupby('UID')['Sleep_Hours_WP'].mean().mean()
        wp_quality_mean = sleep_centered.groupby('UID')['Sleep_Quality_WP'].mean().mean()
        
        log(f"[CHECK] Average within-person mean for Sleep_Hours_WP: {wp_hour_mean:.6f} (should be ~0)")
        log(f"[CHECK] Average within-person mean for Sleep_Quality_WP: {wp_quality_mean:.6f} (should be ~0)")

        log("[DONE] Person-centered variables created")

        # =========================================================================
        # STEP 4: Save Centered Sleep Data
        # =========================================================================
        # Output: Complete dataset with person-mean and within-person variables

        log("[SAVE] Saving centered sleep data...")
        
        # Ensure proper column order
        output_cols = ["UID", "TEST", "Sleep_Hours", "Sleep_Quality", 
                      "Sleep_Hours_PM", "Sleep_Quality_PM", "Sleep_Hours_WP", "Sleep_Quality_WP"]
        sleep_centered_output = sleep_centered[output_cols]
        
        centered_output_path = RQ_DIR / "data" / "step02_sleep_centered.csv"
        sleep_centered_output.to_csv(centered_output_path, index=False, encoding='utf-8')
        log(f"[SAVED] {centered_output_path} ({len(sleep_centered_output)} rows, {len(sleep_centered_output.columns)} cols)")

        # =========================================================================
        # STEP 5: Run Centering Validation
        # =========================================================================
        # Tool: validate_standardization (adapted for centering validation)
        # Validates: Within-person means are approximately zero

        log("[VALIDATION] Running centering validation...")
        
        # Check that within-person variables have mean ~0 within each person
        validation_results = {}
        
        for var in ['Sleep_Hours_WP', 'Sleep_Quality_WP']:
            # Compute person-level means of within-person variables (should be ~0)
            person_wp_means = sleep_centered_output.groupby('UID')[var].mean()
            overall_wp_mean = person_wp_means.mean()
            max_abs_deviation = person_wp_means.abs().max()
            
            # Check if centering worked (tolerance = 0.01)
            centering_valid = abs(overall_wp_mean) <= 0.01 and max_abs_deviation <= 0.01
            
            validation_results[var] = {
                'overall_mean': overall_wp_mean,
                'max_abs_deviation': max_abs_deviation,
                'valid': centering_valid
            }
            
            log(f"[VALIDATION] {var} centering: {'PASS' if centering_valid else 'FAIL'}")
            log(f"[VALIDATION] {var} overall mean: {overall_wp_mean:.6f} (tolerance: ±0.01)")
            log(f"[VALIDATION] {var} max deviation: {max_abs_deviation:.6f} (tolerance: ≤0.01)")

        # Additional validation using tools.validation.validate_standardization
        # Note: We're validating centering (mean=0) not standardization (mean=0, sd=1)
        try:
            standardization_validation = validate_standardization(
                df=sleep_centered_output,
                group_var="UID",
                centered_vars=["Sleep_Hours_WP", "Sleep_Quality_WP"]
            )
            
            if standardization_validation.get('valid', False):
                log("[VALIDATION] Standardization check: PASS")
            else:
                log(f"[VALIDATION] Standardization check: PARTIAL - {standardization_validation.get('message', 'Unknown')}")
                # Note: This may warn about SD≠1, which is expected for centering (not standardizing)
                
        except Exception as e:
            log(f"[VALIDATION] Standardization validation failed: {str(e)}")
            log("[VALIDATION] Continuing with manual centering validation")

        # Overall validation result
        all_centering_valid = all(result['valid'] for result in validation_results.values())
        
        if all_centering_valid:
            log("[VALIDATION] Person centering: PASS")
        else:
            log("[VALIDATION] Person centering: FAIL - centering tolerance exceeded")

        # Scientific Mantra logging between steps
        log("")
        log("=== SCIENTIFIC MANTRA ===")
        log("1. What question did we ask?")
        log("   -> Can we separate between-person and within-person sleep effects?")
        log("2. What did we find?")
        log(f"   -> Person means computed, within-person centering valid: {all_centering_valid}")
        log(f"   -> Sleep_Hours_WP range: {sleep_centered['Sleep_Hours_WP'].min():.2f} to {sleep_centered['Sleep_Hours_WP'].max():.2f}")
        log("3. What does it mean?")
        log("   -> We can now model how deviations from personal sleep patterns affect memory")
        log("4. What should we do next?")
        log("   -> Proceed to step03: extract VR memory performance scores")
        log("=========================")
        log("")

        log("[SUCCESS] Step 02 complete")
        sys.exit(0)

    except Exception as e:
        log(f"[ERROR] {str(e)}")
        log("[TRACEBACK] Full error details:")
        with open(LOG_FILE, 'a', encoding='utf-8') as f:
            traceback.print_exc(file=f)
        traceback.print_exc()
        sys.exit(1)